async (params, browser) => {
  // Open Tinder
  await browser.open('https://tinder.com/app/recs')

  // Wait for cards
  await browser.waitForSelector('[class*="recsCardboard"], main', 15000)

  // Let card render
  await browser.wait(2000)

  // Click like
  const result = await browser.evaluate(`const likeBtn = document.querySelector('[aria-label="Like"], button[class*="recsGamepad__button--like"], button[class*="like"], button[class*="Bgi($g-ds-background-like)"]'); if (likeBtn) { likeBtn.click(); return { success: true, action: 'liked' }; } return { success: false, message: 'Like button not found' };`)

  return result
}
